import { useEffect, useState } from "react";
import axios from "axios";
import { useParams, useNavigate } from "react-router-dom";

export default function DriverRoute() {
  const { id } = useParams();
  const navigate = useNavigate();

  const [task, setTask] = useState(null);

  const getTask = async () => {
    try {
      const res = await axios.get(
        "http://localhost:3000/api/driver/today-task"
      );

      const found = res.data.requests.find(
        (item) => item._id === id
      );

      setTask(found);
    } catch (error) {
      console.log(error);
    }
  };

  useEffect(() => {
    getTask();
  }, []);

  const markArrived = async () => {
    try {
      const res = await axios.put(
        `http://localhost:3000/api/driver/arrived/${id}`
      );

      setTask(res.data.data);
    } catch (error) {
      console.log(error);
    }
  };

  const markCompleted = async () => {
    try {
      const res = await axios.put(
        `http://localhost:3000/api/driver/completed/${id}`
      );

      setTask(res.data.data);

      setTimeout(() => {
        navigate("/driver-dashboard");
      }, 2000);
    } catch (error) {
      console.log(error);
    }
  };

  if (!task) {
    return (
      <div className="min-h-screen flex justify-center items-center text-xl font-bold">
        Loading...
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#4CBB17]/10">

      {/* Header */}
      <div className="bg-green-700 text-white py-4 shadow">
        <h1 className="text-center text-2xl font-bold">
          🚛 Route Navigation
        </h1>
      </div>

      {/* Map Section */}
      <div className="w-full h-[350px] bg-white shadow-md">
        <iframe
          title="Route Map"
          width="100%"
          height="100%"
          className="border-0"
          loading="lazy"
          src={`https://maps.google.com/maps?q=${task.location?.latitude},${task.location?.longitude}&z=15&output=embed`}
        />
      </div>

      {/* Destination */}
      <div className="text-center mt-4">
        <h2 className="text-xl font-bold text-green-800">
          📍 {task.location?.location}
        </h2>
      </div>

      {/* Time Info */}
      <div className="flex flex-col items-center mt-6">

        {task.arrivedAt && (
          <div className="bg-yellow-100 p-4 rounded-xl shadow w-80 text-center mb-4">
            <p className="font-bold text-yellow-700">
              Arrived Time
            </p>

            <p>
              {new Date(task.arrivedAt).toLocaleString()}
            </p>
          </div>
        )}

        {task.completedAt && (
          <div className="bg-green-100 p-4 rounded-xl shadow w-80 text-center mb-4">
            <p className="font-bold text-green-700">
              Completed Time
            </p>

            <p>
              {new Date(task.completedAt).toLocaleString()}
            </p>
          </div>
        )}

        {/* Buttons */}
        {task.status === "Scheduled" && (
          <button
            onClick={markArrived}
            className="bg-yellow-500 hover:bg-yellow-600 text-white px-12 py-4 rounded-xl text-xl font-bold shadow-lg"
          >
            Arrived
          </button>
        )}

        {task.status === "Arrived" && (
          <button
            onClick={markCompleted}
            className="bg-green-600 hover:bg-green-700 text-white px-12 py-4 rounded-xl text-xl font-bold shadow-lg"
          >
            Completed
          </button>
        )}
      </div>
    </div>
  );
}
